#!/usr/bin/env python3
"""Validate the Radi144 Engine Manifest Gate without enabling engine execution."""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any

ROOT = Path(__file__).resolve().parents[1]
MANIFEST = ROOT / "packages" / "contracts" / "engines" / "radi144.engine-manifest.v1.json"
WORKFLOW = ROOT / "packages" / "contracts" / "workflows" / "workflow-manifest.v2.json"
EVENTS = ROOT / "packages" / "contracts" / "events" / "event-registry.v1.json"
SCHEMA = ROOT / "packages" / "contracts" / "schemas" / "engine-manifest.schema.json"

REQUIRED_SUBSTEPS = [
    "radi144.input_context_load",
    "radi144.data_quality_check",
    "radi144.biofield_signature_vectorize",
    "radi144.reference_matrix_load",
    "radi144.compute_path_select",
    "radi144.resonance_matrix_compute",
    "radi144.matrix_normalize",
    "radi144.coherence_extract",
    "radi144.biofield_mapping",
    "radi144.confidence_uncertainty",
    "radi144.synergy_seed_create",
    "radi144.result_persist",
    "radi144.event_audit_complete",
]
REQUIRED_ALGORITHMS = {
    "vectorize_client_context",
    "cosine_resonance_matrix",
    "matrix_symmetrization",
    "biofield_mapping",
    "confidence_uncertainty",
    "synergy_seed",
}
REQUIRED_RESULT_FIELDS = {
    "module_run_id",
    "tenant_id",
    "session_id",
    "workflow_run_id",
    "module_id",
    "algorithm_version",
    "compute_backend",
    "matrix_shape",
    "coherence_scores",
    "biofield_map",
    "confidence",
    "synergy_seed",
    "provenance",
}


def fail(message: str) -> None:
    print(f"[FAIL] {message}")
    raise SystemExit(1)


def require(condition: bool, message: str) -> None:
    if not condition:
        fail(message)


def load(path: Path) -> dict[str, Any]:
    data = json.loads(path.read_text(encoding="utf-8"))
    require(isinstance(data, dict), f"JSON document must be object: {path.relative_to(ROOT)}")
    return data


def main() -> int:
    schema = load(SCHEMA)
    manifest = load(MANIFEST)
    workflow = load(WORKFLOW)
    events = load(EVENTS)

    for key in schema.get("required", []):
        require(key in manifest, f"Radi144 manifest missing required schema key: {key}")

    require(manifest.get("status") == "radi144_engine_manifest_gate_initialized", "Radi144 manifest status drift")
    require(manifest.get("module_id") == "radi144", "Radi144 manifest module_id drift")
    require(manifest.get("phase") == "diagnose", "Radi144 manifest phase must be diagnose")

    runtime_scope = manifest.get("runtime_scope", {})
    require(runtime_scope.get("engine_manifest_enabled") is True, "Radi144 manifest gate must be enabled")
    require(runtime_scope.get("engine_domain_service_enabled") is True, "Radi144 domain service gate must be enabled")
    require(runtime_scope.get("engine_job_contract_enabled") is True, "Radi144 job contract gate must be enabled")
    require(runtime_scope.get("api_job_records_enabled") is True, "Radi144 API job record gate must be enabled")
    require(runtime_scope.get("worker_runtime_enabled") is True, "Radi144 worker runtime service must be enabled")
    require(runtime_scope.get("worker_runtime_service_enabled") is True, "Radi144 worker runtime service must be enabled")
    require(runtime_scope.get("engine_execution_decision_recorded") is True, "Radi144 execution decision must be recorded")
    require(runtime_scope.get("cpu_execution_enabled") is True, "Radi144 CPU-safe execution service must be enabled")
    require(runtime_scope.get("cpu_safe_execution_service_enabled") is True, "Radi144 CPU-safe execution service must be enabled")
    require(runtime_scope.get("worker_cpu_execution_wiring_enabled") is True, "Radi144 worker CPU execution wiring must be enabled")
    require(runtime_scope.get("worker_result_write_enabled") is True, "Radi144 worker result writes must be enabled")
    require(runtime_scope.get("worker_progress_events_enabled") is True, "Radi144 worker progress events must be enabled")
    require(runtime_scope.get("jobtracker_event_binding_enabled") is True, "Radi144 JobTracker event binding must be enabled")
    require(runtime_scope.get("external_queue_decision_recorded") is True, "Radi144 external queue decision must be recorded")
    require(runtime_scope.get("external_queue_enabled") is False, "Radi144 external queue must remain disabled")
    require(runtime_scope.get("daemon_enabled") is False, "Radi144 daemon must remain disabled")
    require(runtime_scope.get("worker_projection_materialization_decision_recorded") is True, "Radi144 worker projection materialization decision must be recorded")
    require(runtime_scope.get("worker_projection_materialization_enabled") is False, "Radi144 worker projection materialization must remain disabled")
    require(runtime_scope.get("materialized_projection_storage_decision_recorded") is True, "Radi144 materialized projection storage decision must be recorded")
    require(runtime_scope.get("materialized_projection_storage_enabled") is False, "Radi144 materialized projection storage must remain disabled")
    require(runtime_scope.get("projection_storage_tables_enabled") is False, "Radi144 projection storage tables must remain disabled")
    require(runtime_scope.get("projection_write_service_enabled") is False, "Radi144 projection write service must remain disabled")
    require(runtime_scope.get("projection_cache_policy_recorded") is True, "Radi144 projection cache policy decision must be recorded")
    require(runtime_scope.get("projection_cache_enabled") is False, "Radi144 projection cache must remain disabled")
    require(runtime_scope.get("projection_cache_storage_enabled") is False, "Radi144 projection cache storage must remain disabled")
    require(runtime_scope.get("projection_cache_write_service_enabled") is False, "Radi144 projection cache write service must remain disabled")
    require(runtime_scope.get("materialized_projection_storage_contract_recorded") is True, "Radi144 materialized projection storage contract must be recorded")
    require(runtime_scope.get("materialized_projection_storage_schema_recorded") is True, "Radi144 materialized projection storage schema must be recorded")
    require(runtime_scope.get("materialized_projection_storage_migration_decision_recorded") is True, "Radi144 materialized projection storage migration decision must be recorded")
    require(runtime_scope.get("alembic_migration_enabled") is False, "Radi144 projection Alembic migration must remain disabled")
    require(runtime_scope.get("orm_model_decision_recorded") is True, "Radi144 projection ORM model decision must be recorded")
    require(runtime_scope.get("relationship_contract_recorded") is True, "Radi144 projection relationship contract must be recorded")
    require(runtime_scope.get("constraints_recorded") is True, "Radi144 projection constraints must be recorded")
    require(runtime_scope.get("model_enablement_decision_recorded") is True, "Radi144 projection model enablement decision must be recorded")
    require(runtime_scope.get("orm_implementation_decision_recorded") is True, "Radi144 projection ORM implementation decision must be recorded")
    require(runtime_scope.get("migration_enablement_decision_recorded") is True, "Radi144 projection migration enablement decision must be recorded")
    require(runtime_scope.get("migration_implementation_decision_recorded") is True, "Radi144 projection migration implementation decision must be recorded")
    require(runtime_scope.get("table_creation_decision_recorded") is True, "Radi144 projection table creation decision must be recorded")
    require(runtime_scope.get("table_contract_decision_recorded") is True, "Radi144 projection table contract decision must be recorded")
    require(runtime_scope.get("ddl_implementation_decision_recorded") is True, "Radi144 projection table DDL implementation decision must be recorded")
    require(runtime_scope.get("alembic_revision_decision_recorded") is True, "Radi144 projection Alembic revision decision must be recorded")
    require(runtime_scope.get("alembic_revision_implementation_decision_recorded") is True, "Radi144 projection Alembic revision implementation decision must be recorded")
    require(runtime_scope.get("migration_file_decision_recorded") is True, "Radi144 projection migration file decision must be recorded")
    require(runtime_scope.get("migration_file_contract_decision_recorded") is True, "Radi144 projection migration file contract decision must be recorded")
    require(runtime_scope.get("migration_file_implementation_decision_recorded") is True, "Radi144 projection migration file implementation decision must be recorded")
    require(runtime_scope.get("migration_file_creation_decision_recorded") is True, "Radi144 projection migration file creation decision must be recorded")
    require(runtime_scope.get("migration_file_content_contract_decision_recorded") is True, "Radi144 projection migration file content contract decision must be recorded")
    require(runtime_scope.get("migration_file_authoring_decision_recorded") is True, "Radi144 projection migration file authoring decision must be recorded")
    require(runtime_scope.get("migration_file_write_decision_recorded") is True, "Radi144 projection migration file write decision must be recorded")
    require(runtime_scope.get("migration_file_write_implementation_decision_recorded") is True, "Radi144 projection migration file write implementation decision must be recorded")
    require(runtime_scope.get("migration_file_introduction_decision_recorded") is True, "Radi144 projection migration file introduction decision must be recorded")
    require(runtime_scope.get("migration_file_introduction_implementation_decision_recorded") is True, "Radi144 projection migration file introduction implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_introduction_decision_recorded") is True, "Radi144 projection migration file repository introduction decision must be recorded")
    require(runtime_scope.get("migration_file_repository_introduction_implementation_decision_recorded") is True, "Radi144 projection migration file repository introduction implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_creation_decision_recorded") is True, "Radi144 projection migration file repository file creation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_creation_implementation_decision_recorded") is True, "Radi144 projection migration file repository file creation implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_write_decision_recorded") is True, "Radi144 projection migration file repository file write decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_write_implementation_decision_recorded") is True, "Radi144 projection migration file repository file write implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_materialization_decision_recorded") is True, "Radi144 projection migration file repository file materialization decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_materialization_implementation_decision_recorded") is True, "Radi144 projection migration file repository file materialization implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_execution_decision_recorded") is True, "Radi144 projection migration file repository file execution decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_execution_implementation_decision_recorded") is True, "Radi144 projection migration file repository file execution implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_enablement_decision_recorded") is True, "Radi144 projection migration file repository file enablement decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_enablement_implementation_decision_recorded") is True, "Radi144 projection migration file repository file enablement implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_activation_decision_recorded") is True, "Radi144 projection migration file repository file activation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_activation_implementation_decision_recorded") is True, "Radi144 projection migration file repository file activation implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_opening_decision_recorded") is True, "Radi144 projection migration file repository file opening decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_opening_implementation_decision_recorded") is True, "Radi144 projection migration file repository file opening implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_release_decision_recorded") is True, "Radi144 projection migration file repository file release decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_release_implementation_decision_recorded") is True, "Radi144 projection migration file repository file release implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_publication_decision_recorded") is True, "Radi144 projection migration file repository file publication decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_publication_implementation_decision_recorded") is True, "Radi144 projection migration file repository file publication implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_finalization_decision_recorded") is True, "Radi144 projection migration file repository file finalization decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_finalization_implementation_decision_recorded") is True, "Radi144 projection migration file repository file finalization implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_closure_decision_recorded") is True, "Radi144 projection migration file repository file closure decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_closure_implementation_decision_recorded") is True, "Radi144 projection migration file repository file closure implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_readiness_decision_recorded") is True, "Radi144 projection migration file repository file readiness decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_readiness_implementation_decision_recorded") is True, "Radi144 projection migration file repository file readiness implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_preflight_decision_recorded") is True, "Radi144 projection migration file repository file preflight decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_preflight_implementation_decision_recorded") is True, "Radi144 projection migration file repository file preflight implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_validation_decision_recorded") is True, "Radi144 projection migration file repository file validation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_validation_implementation_decision_recorded") is True, "Radi144 projection migration file repository file validation implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_approval_decision_recorded") is True, "Radi144 projection migration file repository file approval decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_approval_implementation_decision_recorded") is True, "Radi144 projection migration file repository file approval implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_authorization_decision_recorded") is True, "Radi144 projection migration file repository file authorization decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_authorization_implementation_decision_recorded") is True, "Radi144 projection migration file repository file authorization implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_permission_decision_recorded") is True, "Radi144 projection migration file repository file permission decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_permission_implementation_decision_recorded") is True, "Radi144 projection migration file repository file permission implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_access_decision_recorded") is True, "Radi144 projection migration file repository file access decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_access_implementation_decision_recorded") is True, "Radi144 projection migration file repository file access implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_review_decision_recorded") is True, "Radi144 projection migration file repository file review decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_review_implementation_decision_recorded") is True, "Radi144 projection migration file repository file review implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_acceptance_decision_recorded") is True, "Radi144 projection migration file repository file acceptance decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_acceptance_implementation_decision_recorded") is True, "Radi144 projection migration file repository file acceptance implementation decision must be recorded")
    require(runtime_scope.get("migration_file_repository_file_admission_decision_recorded") is True, "Radi144 projection migration file repository file admission decision must be recorded")
    require(runtime_scope.get("migration_file_enabled") is False, "Radi144 projection migration file must remain disabled")
    require(runtime_scope.get("alembic_revision_file_enabled") is False, "Radi144 projection Alembic revision file must remain disabled")
    require(runtime_scope.get("ddl_implementation_enabled") is False, "Radi144 projection table DDL implementation must remain disabled")
    require(runtime_scope.get("orm_model_enabled") is False, "Radi144 projection ORM model must remain disabled")
    require(runtime_scope.get("storage_implementation_enabled") is False, "Radi144 projection storage implementation must remain disabled")
    require(runtime_scope.get("worker_projection_builder_enabled") is False, "Radi144 worker projection builder must remain disabled")
    require(runtime_scope.get("gpu_cuda_execution_enabled") is False, "Radi144 GPU/CUDA execution must remain disabled")
    require(runtime_scope.get("engine_api_boundary_decided") is True, "Radi144 API boundary decision must be recorded")
    require(runtime_scope.get("engine_api_runtime_routes_enabled") is True, "Radi144 API runtime routes must be enabled")
    require(runtime_scope.get("client_projection_boundary_decided") is True, "Radi144 projection boundary decision must be recorded")
    require(runtime_scope.get("result_persistence_storage_enabled") is True, "Radi144 storage boundary must be enabled")
    require(runtime_scope.get("runtime_result_write_service_enabled") is True, "Radi144 runtime result write service must be enabled")
    require(runtime_scope.get("projection_builder_service_enabled") is True, "Radi144 projection builder service must be enabled")
    require(runtime_scope.get("api_projection_reads_enabled") is True, "Radi144 API projection reads must be enabled")
    require(runtime_scope.get("result_schema_enabled") is True, "Radi144 result schema gate must be enabled")
    for blocked_flag in [
        "worker_jobs_enabled",
        "engine_execution_enabled",
        "engine_api_enabled",
        "result_persistence_enabled",
        "client_projection_enabled",
    ]:
        require(runtime_scope.get(blocked_flag) is False, f"{blocked_flag} must remain false")

    workflows = {item.get("id"): item for item in workflow.get("workflows", [])}
    modules = {item.get("id"): item for item in workflow.get("modules", [])}
    module_contracts = workflow.get("module_contracts", {})
    first_vertical = workflow.get("first_vertical_slice", {})
    require(modules.get("radi144", {}).get("first_vertical") is True, "Workflow manifest must mark Radi144 as first vertical")
    require(first_vertical.get("module_id") == "radi144", "First vertical slice must be Radi144")
    require(set(manifest.get("workflow_bindings", [])) == {"W-A", "W-B"}, "Radi144 workflow bindings must be W-A and W-B")
    for workflow_id in manifest.get("workflow_bindings", []):
        require(workflow_id in workflows, f"Radi144 binds unknown workflow: {workflow_id}")
        order = workflows[workflow_id].get("module_order")
        require(isinstance(order, list) and "radi144" in order, f"Workflow {workflow_id} must include radi144")

    expected_short_substeps = module_contracts.get("radi144", {}).get("substeps", [])
    manifest_short_substeps = [item["id"].replace("radi144.", "") for item in manifest.get("substeps", [])]
    require(manifest_short_substeps == expected_short_substeps, "Radi144 substeps must match workflow manifest order")
    require([item.get("id") for item in manifest.get("substeps", [])] == REQUIRED_SUBSTEPS, "Radi144 detailed substep IDs drift")
    require([item.get("order") for item in manifest.get("substeps", [])] == list(range(1, 14)), "Radi144 substep order must be contiguous 1..13")

    require(REQUIRED_ALGORITHMS.issubset(set(manifest.get("core_algorithms", []))), "Radi144 core algorithms incomplete")
    api_boundary = manifest.get("api_boundary", {})
    require(
        api_boundary.get("instance_path") == "packages/contracts/api/radi144-engine-api-boundary.v1.instance.json",
        "Radi144 API boundary instance path drift",
    )
    require(api_boundary.get("openapi_paths_enabled") is True, "Radi144 API OpenAPI paths must be open after runtime route gate")
    require(api_boundary.get("runtime_routes_enabled") is True, "Radi144 API runtime routes must be open after runtime route gate")

    storage_boundary = manifest.get("storage_boundary", {})
    require(
        storage_boundary.get("instance_path") == "packages/contracts/storage/radi144-result-storage.v1.instance.json",
        "Radi144 storage boundary instance path drift",
    )
    require(storage_boundary.get("storage_enabled") is True, "Radi144 storage models must be enabled")
    require(storage_boundary.get("runtime_writes_enabled") is False, "Radi144 runtime writes must remain blocked")

    write_boundary = manifest.get("runtime_result_write_boundary", {})
    require(
        write_boundary.get("instance_path") == "packages/contracts/storage/radi144-runtime-result-write.v1.instance.json",
        "Radi144 runtime result write boundary instance path drift",
    )
    require(write_boundary.get("write_service_enabled") is True, "Radi144 runtime result write service must be enabled")
    require(write_boundary.get("api_result_writes_enabled") is False, "Radi144 API result writes must remain blocked")

    projection_boundary = manifest.get("client_projection_boundary", {})
    require(
        projection_boundary.get("instance_path") == "packages/contracts/projections/radi144-client-projection.v1.instance.json",
        "Radi144 projection boundary instance path drift",
    )
    require(projection_boundary.get("builder_enabled") is False, "Radi144 projection builder must remain closed")
    require(projection_boundary.get("raw_debug_excluded") is True, "Radi144 projection must exclude raw debug")

    job_contract = manifest.get("job_contract", {})
    require(
        job_contract.get("schema_path") == "packages/contracts/jobs/radi144-engine-job.schema.v1.json",
        "Radi144 job schema path drift",
    )
    require(job_contract.get("worker_runtime_enabled") is False, "Radi144 job must not enable worker runtime")
    require(job_contract.get("engine_execution_enabled") is False, "Radi144 job must not enable execution")

    api_job_boundary = manifest.get("api_job_record_boundary", {})
    require(api_job_boundary.get("api_job_records_enabled") is True, "Radi144 API job records must be enabled")
    require(api_job_boundary.get("worker_runtime_enabled") is False, "Radi144 API job records must not enable worker runtime")
    require(api_job_boundary.get("engine_execution_enabled") is False, "Radi144 API job records must not enable execution")

    worker_runtime_boundary = manifest.get("worker_runtime_boundary", {})
    require(worker_runtime_boundary.get("worker_runtime_service_enabled") is True, "Radi144 worker runtime service must be enabled")
    require(worker_runtime_boundary.get("engine_execution_enabled") is False, "Radi144 worker runtime must not enable execution")
    require(worker_runtime_boundary.get("result_writer_enabled_in_worker") is False, "Radi144 worker runtime must not write results")
    require(worker_runtime_boundary.get("projection_builder_enabled_in_worker") is False, "Radi144 worker runtime must not build projections")

    engine_execution_boundary = manifest.get("engine_execution_boundary", {})
    require(engine_execution_boundary.get("decision") == "defer_execution_until_cpu_safe_gate", "Radi144 execution must be deferred")
    require(engine_execution_boundary.get("engine_execution_enabled") is False, "Radi144 execution must remain disabled")
    require(engine_execution_boundary.get("cpu_execution_enabled") is False, "Radi144 execution decision must remain historically deferred")
    require(engine_execution_boundary.get("gpu_cuda_execution_enabled") is False, "Radi144 GPU/CUDA execution must remain disabled")

    cpu_safe_boundary = manifest.get("cpu_safe_execution_boundary", {})
    require(cpu_safe_boundary.get("cpu_safe_execution_service_enabled") is True, "Radi144 CPU-safe execution service must be enabled")
    require(cpu_safe_boundary.get("compute_backend") == "cpu", "Radi144 CPU-safe backend must be cpu")
    require(cpu_safe_boundary.get("worker_runtime_may_call_service") is False, "Radi144 CPU-safe service boundary must remain historically unwired")
    require(cpu_safe_boundary.get("worker_runtime_may_write_results") is False, "Radi144 CPU-safe service boundary must remain historically write-free")
    require(cpu_safe_boundary.get("gpu_cuda_execution_enabled") is False, "Radi144 GPU/CUDA execution must remain disabled")

    worker_cpu_boundary = manifest.get("worker_cpu_execution_wiring_boundary", {})
    require(worker_cpu_boundary.get("worker_cpu_execution_wiring_enabled") is True, "Radi144 worker CPU execution wiring must be enabled")
    require(worker_cpu_boundary.get("worker_runtime_may_call_cpu_service") is True, "Radi144 worker must call CPU-safe service")
    require(worker_cpu_boundary.get("worker_runtime_may_write_results") is True, "Radi144 worker result writes must be enabled")
    require(worker_cpu_boundary.get("gpu_cuda_execution_enabled") is False, "Radi144 GPU/CUDA execution must remain disabled")

    progress_boundary = manifest.get("worker_progress_event_boundary", {})
    require(progress_boundary.get("worker_progress_events_enabled") is True, "Radi144 worker progress events must be enabled")
    require(progress_boundary.get("forbidden_payload_keys_enforced") is True, "Radi144 worker progress events must enforce payload safety")
    require(progress_boundary.get("gpu_cuda_execution_enabled") is False, "Radi144 GPU/CUDA execution must remain disabled")

    jobtracker_boundary = manifest.get("jobtracker_event_binding_boundary", {})
    require(jobtracker_boundary.get("jobtracker_event_binding_enabled") is True, "Radi144 JobTracker event binding must be enabled")
    require(jobtracker_boundary.get("source_of_truth") == "event_records", "Radi144 JobTracker must use event truth")
    require(jobtracker_boundary.get("api_triggered_execution_enabled") is False, "Radi144 API-triggered execution must remain disabled")

    external_queue_boundary = manifest.get("external_queue_decision_boundary", {})
    require(external_queue_boundary.get("decision") == "defer_external_queue_until_operations_worker_gate", "Radi144 external queue decision must defer")
    require(external_queue_boundary.get("external_queue_enabled") is False, "Radi144 external queue must remain disabled")
    require(external_queue_boundary.get("daemon_enabled") is False, "Radi144 daemon must remain disabled")
    require(external_queue_boundary.get("api_triggered_execution_enabled") is False, "Radi144 API-triggered execution must remain disabled")

    worker_projection_boundary = manifest.get("worker_projection_materialization_decision_boundary", {})
    require(worker_projection_boundary.get("decision") == "defer_worker_projection_materialization_until_storage_contract", "Radi144 worker projection materialization decision must defer")
    require(worker_projection_boundary.get("worker_projection_materialization_enabled") is False, "Radi144 worker projection materialization must remain disabled")
    require(worker_projection_boundary.get("materialized_projection_storage_enabled") is False, "Radi144 materialized projection storage must remain disabled")
    require(worker_projection_boundary.get("worker_projection_builder_enabled") is False, "Radi144 worker projection builder must remain disabled")

